@dataclass(eq=False, repr=False)
class SessionSettingsPatch(betterproto2.Message):
    """
    ApplySettings の部分更新 request。set された field のみ engine に書き込む。
    scalar / bool / string は proto3 `optional` で「未指定」を wire 上で区別する
    (0 / false / "" が有効値のため presence が必須)。access_level は enum 単独で
    presence を表す (UNSPECIFIED=変更しない) ので optional は付けない。
    """

    world_name: "str | None" = betterproto2.field(
        1, betterproto2.TYPE_STRING, optional=True
    )

    world_description: "str | None" = betterproto2.field(
        2, betterproto2.TYPE_STRING, optional=True
    )

    max_users: "int | None" = betterproto2.field(
        3, betterproto2.TYPE_INT32, optional=True
    )

    access_level: "SessionAccessLevel" = betterproto2.field(
        4, betterproto2.TYPE_ENUM, default_factory=lambda: SessionAccessLevel(0)
    )
    """
    UNSPECIFIED=変更しない。それ以外は新しい access level。
    """

    hide_from_listing: "bool | None" = betterproto2.field(
        5, betterproto2.TYPE_BOOL, optional=True
    )

    mobile_friendly: "bool | None" = betterproto2.field(
        6, betterproto2.TYPE_BOOL, optional=True
    )

    away_kick_enabled: "bool | None" = betterproto2.field(
        7, betterproto2.TYPE_BOOL, optional=True
    )

    away_kick_minutes: "float | None" = betterproto2.field(
        8, betterproto2.TYPE_FLOAT, optional=True
    )

    auto_save_enabled: "bool | None" = betterproto2.field(
        9, betterproto2.TYPE_BOOL, optional=True
    )

    auto_save_interval_minutes: "float | None" = betterproto2.field(
        10, betterproto2.TYPE_FLOAT, optional=True
    )

    auto_cleanup_enabled: "bool | None" = betterproto2.field(
        11, betterproto2.TYPE_BOOL, optional=True
    )

    auto_cleanup_interval_seconds: "float | None" = betterproto2.field(
        12, betterproto2.TYPE_FLOAT, optional=True
    )

    replace_tags: "bool" = betterproto2.field(13, betterproto2.TYPE_BOOL)
    """
    tags は「全置換」セマンティクス。repeated に optional は付けられないため
    bool gate で制御する: replace_tags=true のときだけ tags を全置換する
    (空配列で全消し可能)。replace_tags=false なら tags は無視。
    """

    tags: "list[str]" = betterproto2.field(14, betterproto2.TYPE_STRING, repeated=True)

    resonite_link_enabled: "bool | None" = betterproto2.field(
        15, betterproto2.TYPE_BOOL, optional=True
    )
    """
    ResoniteLink の有効化。true で engine の World.StartResoniteLink() を呼ぶ
    (host + ResoniteLink 権限が必須、冪等)。**engine は runtime での無効化を
    提供しない** (dash UI にも Enable ボタンのみ) ため、false を送ると Service は
    FailedPrecondition を返す。未指定なら変更しない。
    """


default_message_pool.register_message(
    "resonite_io.v1", "SessionSettingsPatch", SessionSettingsPatch
)


